module top_module (
    input clk,
    input sreset,
    input [5:0] reset_value,
    output [5:0] q );reg [5:0] count_reg;

    always @(posedge clk) begin
        if (sreset)
            count_reg <= reset_value;
        else
            count_reg <= count_reg + 1;
    end

    assign q = count_reg;

endmodule
